e2c4bf74  // the v2 harness.yaml with this exact shape. If someone ever re-flattens this
e36a5f63  // to a bare string field, the type-checker catches it here.
a2c23396  //
d0e3abea  // Telemetry: every retry decision emits an event via @emmy/telemetry.emitEvent
01e003eb  // (Wave-0 no-op body; Phase 3 replaces it with atomic JSONL append). SC-3's
9b2fc79f  // parse-rate metric is computed from these events in Plan 08's corpus replay:
5f51a609  //   - grammar.retry              : trigger (first-pass parse failure)
9b16c5d3  //   - grammar.retry.success      : retry parsed cleanly
4df2ef42  //   - grammar.retry.exhausted    : retry still malformed OR no grammar configured
5d043d99  // Every event carries `profile: profile.ref` (Shared Pattern 3/4).
e3b0c442  
7571c723  import { readFileSync } from "node:fs";
f84a38b0  import { join } from "node:path";
7ab9a459  import { emitEvent } from "@emmy/telemetry";
3d34e73a  import { GrammarRetryExhaustedError, ProviderError } from "./errors";
58f9b94b  import { postChat } from "./http";
d3fa97e7  import type { ChatRequest, ChatResponse, ProfileSnapshot, ToolCall } from "./types";
e3b0c442  
8d64a30d  /**
2856c34a   * Retry-state shape the before_provider_request hook consumes to decide whether
546b8996   * to inject `extra_body.guided_decoding.grammar_str` for the current request.
533a9f11   */
94fff1c7  export interface RetryState {
979087b6  	wantsGrammar: boolean;
d10b36aa  }
e3b0c442  
14943573  // Intentional: pure WeakMap semantics — GC handles the entry lifetime correctly.
cd14051a  // Each request's AbortSignal is the key; when the signal is discarded (typically
8cf60ec0  // at response-stream close) the corresponding entry becomes unreachable. There is
7eb9b471  // no size cap, no explicit eviction, no manual bookkeeping — long-running sessions
55053dc5  // are bounded by request-level AbortSignal lifetime.
66e3307e  // See grammar-retry.weakmap.test.ts for the guard test.
d952a742  const _retryStateMap: WeakMap<AbortSignal, RetryState> = new WeakMap();
e3b0c442  
8d64a30d  /**
25ee3c25   * Read the retry state associated with a given AbortSignal. Returns undefined
f0eabcca   * if no state has been stored against this signal. Pure WeakMap semantics —
5c091a7a   * never does size-bounded eviction.
533a9f11   */
3e18c3ef  export function getRetryStateForSignal(signal: AbortSignal): RetryState | undefined {
cf62548f  	return _retryStateMap.get(signal);
d10b36aa  }
e3b0c442  
8d64a30d  /**
612a7f5a   * Associate retry state with a given AbortSignal. Later reads via
268617d0   * getRetryStateForSignal return this value while `signal` is reachable;
2a860a3b   * once `signal` is GC'd the entry becomes unreachable automatically.
533a9f11   */
080327bc  export function setRetryStateForSignal(signal: AbortSignal, state: RetryState): void {
7ceded9e  	_retryStateMap.set(signal, state);
d10b36aa  }
e3b0c442  
8d64a30d  /**
c658ece6   * Reactive grammar retry path (D-11 / CLAUDE.md Pitfall #6).
64e75266   *
d1382a83   * 1. Parse unconstrained first. Most turns never pay the grammar cost.
23452f4f   * 2. If any tool_call.arguments is not valid JSON, retry ONCE with
1fa63457   *    `extra_body.guided_decoding.grammar` populated. Grammar path resolved
7a4b9ac6   *    from `profile.harness.tools.grammar.path` (nested shape per D-11; B3 fix)
4f72704f   *    against `profile.ref.path`.
73b9a0b7   * 3. Emit telemetry events on every retry decision so SC-3's parse-rate
d5fd9c4a   *    metric can be computed by counting events in the corpus replay.
64e75266   *
7d595147   * Retry budget is hard-coded to 1 at the provider level.
93d03bea   * `profile.harness.agent_loop.retry_on_unparseable_tool_call` is the AGENT
bf2f44f1   * LOOP's retry budget (Plan 04), not this one. This function handles a single
5df000f0   * wire-format parse failure and returns.
533a9f11   */
009dc97a  export async function callWithReactiveGrammar(
3fc75565  	baseUrl: string,
eca4f76a  	req: ChatRequest,
fb3a4e1d  	profile: ProfileSnapshot,
dc54edf8  	opts: { turnId?: string } = {},
c9277898  ): Promise<{ response: ChatResponse; retried: boolean; reason?: string }> {
431e8148  	const firstResp = await postChat(baseUrl, req);
6de7e5c7  	const toolCalls = firstResp.choices[0]?.message?.tool_calls;
9c171ede  	if (!toolCalls || toolCalls.length === 0) {
cd9829e2  		return { response: firstResp, retried: false };
a32a3bb7  	}
4cee71f4  	const parseFailure = firstBadArgument(toolCalls);
0d1eae3f  	if (!parseFailure) {
cd9829e2  		return { response: firstResp, retried: false };
a32a3bb7  	}
e3b0c442  
2785aa81  	// --- RETRY trigger event — always emitted on first-pass parse failure ---
81f38bfc  	emitEvent({
b4b9d0ff  		event: "grammar.retry",
01ecdf58  		ts: new Date().toISOString(),
de073ff4  		profile: profile.ref,
85b5eacd  		reason: "parse_failure",
0e79aba3  		attempt: 1,
b2ae0ae0  		...(opts.turnId !== undefined ? { turn_id: opts.turnId } : {}),
eeb33785  	});
e3b0c442  
fb828172  	// B3 FIX: consume nested shape profile.harness.tools.grammar.{path, mode}.
e51acb87  	// Retry is impossible if grammar is null OR mode is "disabled".
959d3af3  	const grammarConfig = profile.harness.tools.grammar;
ffb569fe  	if (grammarConfig === null || grammarConfig.mode === "disabled") {
cd01d94e  		emitEvent({
6c959c62  			event: "grammar.retry.exhausted",
64b70a1b  			ts: new Date().toISOString(),
ec268705  			profile: profile.ref,
f80838c4  			reason: "no_grammar_configured",
b87cc2d9  			attempt: 1,
c50ba66b  			...(opts.turnId !== undefined ? { turn_id: opts.turnId } : {}),
206aa438  		});
f69634fe  		throw new ProviderError(
ee636169  			"grammar.retry",
6a9c1865  			`tool-call arguments unparseable and harness.tools.grammar is ${
81bfdcf7  				grammarConfig === null
c908bc5f  					? "null"
3f99a63c  					: `mode=${grammarConfig.mode}`
3b1c6c57  			} (profile ${profile.ref.id}@${profile.ref.version})`,
80e5ba03  		);
a32a3bb7  	}
e3b0c442  
af91282c  	const grammarPath = join(profile.ref.path, grammarConfig.path);
2e27fa1a  	let grammarText: string;
debaf31e  	try {
7e768d7b  		grammarText = readFileSync(grammarPath, "utf8");
c2ac4757  	} catch (e) {
f69634fe  		throw new ProviderError(
ee636169  			"grammar.retry",
a04c799e  			`grammar file not found: ${grammarPath} (${
00dda30b  				e instanceof Error ? e.message : String(e)
c87e17de  			})`,
80e5ba03  		);
a32a3bb7  	}
e3b0c442  
4aff535e  	const retryReq: ChatRequest = {
5e1200b9  		...req,
a783297c  		extra_body: {
de44e3f8  			...(req.extra_body ?? {}),
570828ac  			guided_decoding: { grammar: grammarText },
b7fa8888  		},
d5130ff6  	};
f913be05  	const retryResp = await postChat(baseUrl, retryReq);
7064d55b  	const retryToolCalls = retryResp.choices[0]?.message?.tool_calls ?? [];
93ed1eea  	const stillBad = firstBadArgument(retryToolCalls);
17eac6b9  	if (stillBad) {
cd01d94e  		emitEvent({
6c959c62  			event: "grammar.retry.exhausted",
64b70a1b  			ts: new Date().toISOString(),
ec268705  			profile: profile.ref,
75a0b905  			reason: "parse_failure",
b87cc2d9  			attempt: 1,
c50ba66b  			...(opts.turnId !== undefined ? { turn_id: opts.turnId } : {}),
206aa438  		});
ca35b4c8  		throw new GrammarRetryExhaustedError(1, "parse_failure");
a32a3bb7  	}
81f38bfc  	emitEvent({
5d1e248b  		event: "grammar.retry.success",
01ecdf58  		ts: new Date().toISOString(),
de073ff4  		profile: profile.ref,
85b5eacd  		reason: "parse_failure",
0e79aba3  		attempt: 1,
b2ae0ae0  		...(opts.turnId !== undefined ? { turn_id: opts.turnId } : {}),
eeb33785  	});
ecafe2ed  	return { response: retryResp, retried: true, reason: "parse_failure" };
d10b36aa  }
e3b0c442  
dbc26f6f  function firstBadArgument(toolCalls: ToolCall[]): string | null {
d8a8bb08  	for (const tc of toolCalls) {
131bbee0  		try {
ead546f5  			JSON.parse(tc.function.arguments);
3dbe4bd7  		} catch (_e) {
5135bb4d  			return tc.function.name;
3713bbfd  		}
a32a3bb7  	}
36402414  	return null;
d10b36aa  }
